        </table>
      </div>

      {/* Pagination */}
      <div className="flex items-center justify-between pt-2">
        <button 
          onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
          disabled={currentPage === 1}
          className="px-3 py-1 border border-slate-300 rounded-md text-sm hover:bg-slate-50 disabled:opacity-50 transition-all"
        >
          Previous
